using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.UnitTests;/// <summary>/// Bad case: Try to revoke non-existent consent/// Expected: 404 Not Found/// </summary>public class ConsentServiceTests_RevokeConsent_WithFakeId_ShouldReturnNotFound : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "ConsentService"    };    [SkippableFact]    public async Task RevokeConsent_WithFakeId_ShouldReturnNotFound()    {        await AuthenticateAsPatientAsync(ConsentClient);        var fakeConsentId = Guid.NewGuid();        var revokeRequest = new { reason = "Test revoke non-existent" };        var response = await PostAsJsonWithRetryAsync(            ConsentClient,             ApiEndpoints.Consents.Revoke(fakeConsentId),             revokeRequest);        Assert.True(            response.StatusCode == HttpStatusCode.NotFound ||             response.StatusCode == HttpStatusCode.BadRequest,            $"Expected 404 or 400, got {response.StatusCode}");    }}